<script lang="ts">
  const html: string = "<h1>Scroller</h1>\n\n<p>A scrollytelling container with step-based foreground and background composition. The background content sticks in the viewport while foreground steps scroll over it, with the current step index driving background content changes.</p>\n\n<p>This headless component uses a <code>&lt;div&gt;</code> element with an optional <code>aria-label</code> to create a scrollytelling region with separate background and foreground slots.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Uses <code>&lt;div&gt;</code> element with class <code>scroller</code></li>\n<li>Background content sticks in viewport while foreground steps scroll over it</li>\n<li>Current step index drives background content changes</li>\n<li>Builds on ScrollerBase primitive internally</li>\n<li>Background uses position: sticky; foreground overlays with pointer-events: none on non-interactive areas</li>\n<li>Steps can contain any content (text, images, charts)</li>\n</ul>\n\n<h2>Props</h2>\n\n<ul>\n<li><code>children</code>: slot (required) -- foreground step content</li>\n<li><code>background</code>: slot (required) -- sticky background content that changes with steps</li>\n<li><code>offset</code>: number (default: 0.5) -- viewport offset where step triggers</li>\n<li><code>index</code>: number (bindable, default: 0) -- current active step index</li>\n<li><code>progress</code>: number (bindable, default: 0) -- overall scroll progress (0-1)</li>\n<li><code>label</code>: string (optional) -- accessible label for the scroller region</li>\n<li><code>...restProps</code>: Any additional HTML attributes</li>\n</ul>\n\n<h2>Usage</h2>\n\n<pre><code class=\"language-html\">&lt;Scroller label=\"Climate change data story\" bind:index&gt;\n  &lt;div slot=\"background\"&gt;\n    &lt;!-- Changes based on index --&gt;\n    &lt;img src=\"chart-{index}.png\" alt=\"Chart showing step {index}\" /&gt;\n  &lt;/div&gt;\n  &lt;div class=\"step\"&gt;\n    &lt;p&gt;In 2020, temperatures rose significantly.&lt;/p&gt;\n  &lt;/div&gt;\n  &lt;div class=\"step\"&gt;\n    &lt;p&gt;By 2025, the trend accelerated.&lt;/p&gt;\n  &lt;/div&gt;\n&lt;/Scroller&gt;</code></pre>\n\n<pre><code class=\"language-html\">&lt;Scroller label=\"How a vaccine works\" bind:index bind:progress&gt;\n  &lt;div slot=\"background\"&gt;\n    &lt;Animation frame={index} progress={progress} /&gt;\n  &lt;/div&gt;\n  &lt;div class=\"step\"&gt;\n    &lt;p&gt;The vaccine enters the body.&lt;/p&gt;\n  &lt;/div&gt;\n  &lt;div class=\"step\"&gt;\n    &lt;p&gt;It triggers an immune response.&lt;/p&gt;\n  &lt;/div&gt;\n  &lt;div class=\"step\"&gt;\n    &lt;p&gt;Antibodies are produced.&lt;/p&gt;\n  &lt;/div&gt;\n&lt;/Scroller&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>Standard scroll behavior</li>\n<li>Tab navigates focusable content within steps</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li><code>aria-label</code> on container when <code>label</code> prop is provided</li>\n<li><code>aria-live=\"polite\"</code> on background for screen reader updates when content changes</li>\n</ul>\n\n<h2>Composition</h2>\n\n<ul>\n<li>Uses ScrollerBase internally as the scroll-tracking primitive</li>\n<li>Background slot receives the current index and progress for content switching</li>\n<li>Foreground children are passed through to ScrollerBase as steps</li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Use for data-driven storytelling where visuals change as the reader scrolls</li>\n<li>Use when presenting a narrative with a fixed visual that evolves alongside explanatory text</li>\n<li>Use for interactive articles, data journalism, and educational content</li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Do not use for simple reveal animations -- use a simpler scroll-triggered approach</li>\n<li>Do not use when content does not benefit from scroll-driven narrative</li>\n<li>Do not use for video-driven stories -- use ScrollerVideo instead</li>\n</ul>\n\n<h2>Headless</h2>\n\n<p>This component provides a <code>&lt;div&gt;</code> element with foreground/background composition and scroll tracking, with zero visual styling. The consumer is responsible for all CSS including background stickiness, foreground overlay positioning, step spacing, and responsive layout.</p>\n\n<h2>Styles</h2>\n\n<p>The consumer provides all CSS styling. The component renders with a <code>.scroller</code> class for targeting. No default styles are included -- this is a fully headless component.</p>\n\n<h2>Testing</h2>\n\n<ul>\n<li>Verify the component renders a <code>&lt;div&gt;</code> element with class <code>scroller</code></li>\n<li>Verify <code>aria-label</code> is applied when label prop is provided</li>\n<li>Verify background slot content is rendered</li>\n<li>Verify foreground step content is rendered</li>\n<li>Verify index updates as steps scroll into view</li>\n<li>Verify progress updates as the user scrolls</li>\n<li>Verify <code>aria-live=\"polite\"</code> is on the background region</li>\n<li>Verify pass-through attributes are applied</li>\n</ul>\n\n<h2>Advice</h2>\n\n<ul>\n<li><strong>Designers</strong>: Design background visuals that transition meaningfully between steps. Ensure foreground text has sufficient contrast against the background at every step. Consider reduced-motion preferences for animated backgrounds.</li>\n<li><strong>Developers</strong>: Always provide a descriptive <code>label</code> prop for screen reader landmark navigation. Ensure background content updates are communicated via <code>aria-live</code>. Test with keyboard-only and screen reader navigation.</li>\n</ul>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>scroller-base</code> — see components.tsv</li>\n<li><code>scroller-video</code> — see components.tsv</li>\n<li><code>horizontal-scroller</code> — see components.tsv</li>\n<li><code>carousel</code> — a slideshow for cycling through content items</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li>Reuters Graphics Scroller</li>\n<li>Scrollytelling best practices</li>\n<li>ScrollerBase component: ../scroller-base/index.md</li>\n</ul>";
  // BEGIN auto-generated component example consts
  const demoHtml: string = "<div class=\"scroller\" aria-label=\"a scrollytelling container with step-based foreground and background composition\">Scroller</div>";
  const svelteSource: string = "// In your Svelte component:\nimport Scroller from \"lily-design-system-svelte-headless/components/Scroller/Scroller.svelte\";\n\n<Scroller>\n  <!-- content -->\n</Scroller>\n";
  // END auto-generated component example consts
</script>

